import{_ as o,o as t,c as r,a3 as a}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"51. Recall Without Return To Workplace","description":"","frontmatter":{"title":"51. Recall Without Return To Workplace","eba":"Nurses and Midwives 2024-2028","topics":["hours","overtime"]},"headers":[],"relativePath":"ebas/nurses-midwives/hours-of-work/51-recall-without-return-to-workplace.md","filePath":"ebas/nurses-midwives/hours-of-work/51-recall-without-return-to-workplace.md"}'),i={name:"ebas/nurses-midwives/hours-of-work/51-recall-without-return-to-workplace.md"};function s(l,e,n,u,c,h){return t(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="_51-recall-without-return-to-workplace" tabindex="-1">51. Recall Without Return To Workplace <a class="header-anchor" href="#_51-recall-without-return-to-workplace" aria-label="Permalink to &quot;51. Recall Without Return To Workplace&quot;">​</a></h1><p><strong>51.1</strong> Where recall to duty can be managed without the Employee having to return to their workplace, such as by telephone or computer, the Employee will be paid a minimum of 1 hour at the appropriate overtime rate for each occasion, provided that multiple recalls within a discrete hour will not attract additional payment.</p><p><strong>51.2</strong> Where the Employee is due to commence rostered ordinary hours within 4 hours of the completion of the last recall, and the cumulative recall work in the 8 hours immediately preceding rostered duty meets the following criteria:</p><p><strong>(a)</strong> has exceeded two hours work (rather than the time paid); or</p><p><strong>(b)</strong> comprises 3 or more recalls over a period of 4 hours or more,</p><p>The Employer will:</p><p><strong>(c)</strong> not require the Employee to resume or to continue to work without having had 10 consecutive hours off duty without loss of pay for rostered ordinary hours; or</p><p><strong>(d)</strong> pay the Employee at the rate of double time until released from duty for 10 consecutive hours, without loss of pay for rostered ordinary hours occurring during such absence.</p>',8)])])}const m=o(i,[["render",s]]);export{d as __pageData,m as default};
